    //HS: Code added to track page events when user lands on Offer Presentment, Payment info or Confirmation Page for abandon email campaign
    const fireSalesFlowEvent = () => {
        SalesforceInteractions.util.resolveWhenTrue.bind(() => {
            // Only return true when the Adobe object and core variables are actually present
            if (window._satellite && typeof window._satellite.getVar === "function") {
                const componentName = window._satellite.getVar("core:cc:shared:componentName");
                const flowName = window._satellite.getVar("core:cc:shared:flowName") ;
                // Return true when data is ready
                return (componentName && componentName !== '' && componentName !== '[unknown]' && flowName && flowName !== '' && flowName !== '[unknown]') ? true : false;
            }
            return false;
        }, undefined, 5000, 100).then(() => {
            // Re-grab the variables 
            const componentName = window._satellite.getVar("core:cc:shared:componentName") ? window._satellite.getVar("core:cc:shared:componentName").toLowerCase() : "";
            const flowName = window._satellite.getVar("core:cc:shared:flowName") ? window._satellite.getVar("core:cc:shared:flowName").toLowerCase() : "";
            const customerType = window._satellite.getVar("core:cc:shared:customerType") ? window._satellite.getVar("core:cc:shared:customerType").toLowerCase() : "";
            const customerESN = window._satellite.getVar("core:cc:globalESN");
            let salesFlowEvent = 'Salesflow Data Capture';

            // Construct attributes object dynamically to avoid overwriting with empty values
            const userAttributes = {};
            
            if (customerType) userAttributes.customerTypeWeb = customerType;
            if (componentName) userAttributes.componentName = componentName;
            if (flowName) userAttributes.flowName = flowName;
            //Do not capture RadioId frpom DL if captured via URL
            if (customerESN && dncRadioIdFromDL == false) userAttributes.radioId = customerESN; 

            if (salesFlowEvent) {
                console.log('salesFlowEvent ' + salesFlowEvent)
                SalesforceInteractions.sendEvent({
                    interaction: { name: salesFlowEvent},
                    user: { attributes: userAttributes }
                });
            }
        }).catch((err) => {
            console.warn("Adobe variables timed out.", err);
        });
    };
   fireSalesFlowEvent();

