try {
    (function () {
        const TARGET_CURRENT_PLAN = "Select - 1mo - wActv|Promo $5.99/mo Select for 12mos";
        const TARGET_FIRST_OFFER_PLAN = "Select - 1mo - wActv|Promo $5.99/mo Select for 12mos";
        const TARGET_FIRST_OFFER_PRICE_TEXT = "$5.99/mo for 12 months"; // optional UI text only
        const TARGET_FIRST_OFFER_PRICE = 5.99; // optional numeric check

function currentPlanOk() {
  const plans = window.digitalData?.planInfo?.products?.currentPlanCodes || [];
  if (!Array.isArray(plans)) return false;

  function norm(s) {
    return String(s || "").toLowerCase();
  }

  return plans.some(p => {
    const code = norm(p?.code ?? p);

    const hasSelect = code.includes("select");
    const hasEssential = code.includes("essential");
    const hasPromo = code.includes("promo");
    const hasTrial = code.includes("trial");
    const hasAdvantage = code.includes("advantage");

    // Global exclusion for BOTH segments
    if (hasAdvantage) return false;

    // -------------------------
    // SEGMENT 1 (M&E Discount Incoming)
    // (select AND promo AND NOT trial)
    // OR (essential AND promo)
    // -------------------------
    const segment1 =
      (hasSelect && hasPromo && !hasTrial) ||
      (hasEssential && hasPromo);

    // -------------------------
    // SEGMENT 2 (M&E FP Incoming)
    // (select AND NOT promo AND NOT trial)
    // OR (essential AND NOT promo)
    // -------------------------
    const segment2 =
      (hasSelect && !hasPromo && !hasTrial) ||
      (hasEssential && !hasPromo);

    // FINAL: Segment 1 OR Segment 2
    return segment1 || segment2;
  });
}

    function findLatestOffersPresented() {
        const arr = window.appEventData || [];
        for (let i = arr.length - 1; i >= 0; i--) {
            if (arr[i]?.event === "offers-presented") return arr[i];
        }
        return null;
    }

    function computeEligibility(evt) {
        const offers = evt?.offerInfo?.offers;
        if (!Array.isArray(offers)) {
            return { eligible: false, offerCount: 0, reason: "no_offers_array" };
        }

        const offerCount = offers.length;
        if (offerCount !== 2) {
            // key rule: exactly 2 indicates "single offer" in your flow
            return { eligible: false, offerCount, reason: "not_exactly_2" };
        }

        const first = offers[0] || {};
        const firstPlanOk = (first.planCode || "") === TARGET_FIRST_OFFER_PLAN;

        // Optional extra validation: price check (use if stable)
        const priceOk =
            typeof first.price === "number" ? first.price === TARGET_FIRST_OFFER_PRICE : true;

        return {
            eligible: firstPlanOk && priceOk,
            offerCount,
            reason: (firstPlanOk ? "ok" : "first_offer_not_target")
        };
    }
    function sendEligibility(elig) {
        try {
            // compute plan / eligibility first
            const planOK = currentPlanOk();
            const finalEligible = !!(planOK && elig && elig.eligible);

            // De-dupe so we don't spam events in SPA
            const sig = `${finalEligible}|${elig?.offerCount || 0}|${elig?.reason || ''}|${planOK}`;
            if (window.__cecmCancelEligSig === sig) return;
            window.__cecmCancelEligSig = sig;

            // Store locally for template guard / campaign checks
            window.__cecmCancelEligibility = {
                eligible: finalEligible,
                currentPlanOk: planOK,
                offerCount: elig?.offerCount || 0,
                reason: elig?.reason || ''
            };

            // Build profile attrs AFTER computing finalEligible
            const profileAttrs = {
            cancelOfferEligible: finalEligible,
            cancelOfferCurrentPlanOk: planOK,
            cancelOfferPresentedCount: elig?.offerCount || 0,
            cancelOfferReason: elig?.reason || ''
            };

            // Send an explicit profile-update event (safe, deduped above)
            try {
            SalesforceInteractions.sendEvent({
                interaction: { name: "cancel_offer_eligibility_evaluated" },
                user: { attributes: profileAttrs }
            });
                // helpful debug
                console.log("[MCP] cancel eligibility sent:", profileAttrs);
            } catch (sendErr) {
                // do not allow a send failure to bubble up
                console.warn("[MCP] failed to send cancel eligibility event:", sendErr);
            }

            } catch (e) {
                // avoid breaking downstream MCP execution
                console.error("[MCP] sendEligibility unexpected error:", e);
            }
        }

        // Evaluate immediately if already present
        const existing = findLatestOffersPresented();
        if (existing) sendEligibility(computeEligibility(existing));

        // Hook future pushes (offers-presented arrives async)
        const arr = (window.appEventData = window.appEventData || []);
        if (!window.__cecmOffersHookedFirstOffer) {
            window.__cecmOffersHookedFirstOffer = true;
            const originalPush = arr.push;
            arr.push = function () {
                const result = originalPush.apply(arr, arguments);
                const lastArg = arguments[arguments.length - 1];
                if (lastArg?.event === "offers-presented") {
                sendEligibility(computeEligibility(lastArg));
                }
                return result;
            };
        }
    })();
    } catch (e) {
        console.log("[MCP] cancel offer eligibility hook failed:", e);
    }

